  ON CONFLICT (num) DO UPDATE SET
    x = EXCLUDED.x, y = EXCLUDED.y, w = EXCLUDED.w, h = EXCLUDED.h,
    status = EXCLUDED.status, open_wo = EXCLUDED.open_wo,
    address = EXCLUDED.address, street = EXCLUDED.street, units = EXCLUDED.units,
    year_built = EXCLUDED.year_built, roof_year = EXCLUDED.roof_year,
    insurance_status = EXCLUDED.insurance_status, notes = EXCLUDED.notes;

  ON CONFLICT (id) DO UPDATE SET
    building = EXCLUDED.building, unit = EXCLUDED.unit, address = EXCLUDED.address,
    beds = EXCLUDED.beds, baths = EXCLUDED.baths, sqft = EXCLUDED.sqft,
    occupancy = EXCLUDED.occupancy, owner_name = EXCLUDED.owner_name,
    owner_phone = EXCLUDED.owner_phone, owner_email = EXCLUDED.owner_email,
    tenant_name = EXCLUDED.tenant_name, tenant_phone = EXCLUDED.tenant_phone,
    tenant_email = EXCLUDED.tenant_email;
  